// Calculate vendor risk metrics from document portfolio
const documents = $input.all().map(item => item.json);
const webhookData = $('Webhook Trigger').first().json;
const now = new Date();

let totalDocs = 0;
let expiredDocs = 0;
let expiringDocs = 0;
let missingTypes = [];
let totalContractValue = 0;
let activeContracts = 0;
let latestComplianceScores = [];
let documentTypes = new Set();

const requiredDocTypes = [
  'insurance_policy', 'business_license', 'certificate_of_insurance',
  'tax_filing', 'bond', 'w9'
];

for (const doc of documents) {
  if (!doc.document || !doc.document.fields) continue;
  const fields = doc.document.fields;
  totalDocs++;

  const docType = fields.document_type?.stringValue || '';
  documentTypes.add(docType);

  // Check expiration
  const expDate = fields.expiration_date?.stringValue;
  if (expDate) {
    const exp = new Date(expDate);
    if (exp < now) {
      expiredDocs++;
    } else if ((exp - now) < 30 * 24 * 60 * 60 * 1000) {
      expiringDocs++;
    }
  }

  // Sum contract values
  const amount = parseFloat(fields.contract_value?.doubleValue || fields.contract_value?.integerValue || 0);
  if (amount > 0) {
    totalContractValue += amount;
    if (!expDate || new Date(expDate) > now) {
      activeContracts++;
    }
  }

  // Collect compliance scores
  const score = parseInt(fields.compliance_score?.integerValue || 0);
  if (score > 0) {
    latestComplianceScores.push(score);
  }
}

// Identify missing required document types
for (const reqType of requiredDocTypes) {
  if (!documentTypes.has(reqType)) {
    missingTypes.push(reqType);
  }
}

// Calculate risk sub-scores
const expiredRatio = totalDocs > 0 ? expiredDocs / totalDocs : 0;
const documentCoverageScore = Math.max(0, 100 - (missingTypes.length * 15));
const expirationRiskScore = Math.max(0, 100 - (expiredRatio * 100) - (expiringDocs * 10));
const avgComplianceScore = latestComplianceScores.length > 0
  ? latestComplianceScores.reduce((a, b) => a + b, 0) / latestComplianceScores.length
  : 50;

return [{
  json: {
    vendor_id: webhookData.vendor_id || webhookData.entity_id,
    vendor_name: webhookData.vendor_name || webhookData.entity_name || '',
    metrics: {
      total_documents: totalDocs,
      expired_documents: expiredDocs,
      expiring_documents: expiringDocs,
      expired_ratio: Math.round(expiredRatio * 100) / 100,
      missing_document_types: missingTypes,
      document_types_present: Array.from(documentTypes),
      total_contract_value: totalContractValue,
      active_contracts: activeContracts,
      avg_compliance_score: Math.round(avgComplianceScore),
      document_coverage_score: documentCoverageScore,
      expiration_risk_score: Math.round(expirationRiskScore)
    },
    calculated_at: new Date().toISOString()
  }
}];

