// Compute final vendor risk score combining metrics and AI assessment
const metricsData = $('Calculate Risk Metrics').first().json;
const geminiResponse = $input.first().json;

let aiAssessment = {};
try {
  const text = geminiResponse.candidates[0].content.parts[0].text;
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  aiAssessment = JSON.parse(cleaned);
} catch (e) {
  aiAssessment = {
    risk_narrative: 'AI assessment unavailable. Manual review recommended.',
    key_risks: [],
    strengths: [],
    action_items: [],
    vendor_tier: 'watch_list',
    recommended_review_frequency: 'monthly'
  };
}

const metrics = metricsData.metrics;

// Weighted risk score calculation (0-100, higher = better/lower risk)
const weights = {
  document_coverage: 0.25,
  expiration_risk: 0.30,
  compliance_score: 0.30,
  ai_tier_bonus: 0.15
};

const tierScores = {
  'preferred': 95,
  'standard': 75,
  'watch_list': 45,
  'probation': 20
};

const aiTierScore = tierScores[aiAssessment.vendor_tier] || 50;

const finalScore = Math.round(
  (metrics.document_coverage_score * weights.document_coverage) +
  (metrics.expiration_risk_score * weights.expiration_risk) +
  (metrics.avg_compliance_score * weights.compliance_score) +
  (aiTierScore * weights.ai_tier_bonus)
);

const riskLevel = finalScore >= 80 ? 'low' : finalScore >= 60 ? 'medium' : finalScore >= 40 ? 'high' : 'critical';

return [{
  json: {
    vendor_id: metricsData.vendor_id,
    vendor_name: metricsData.vendor_name,
    risk_score: finalScore,
    risk_level: riskLevel,
    metrics: metrics,
    ai_assessment: aiAssessment,
    vendor_tier: aiAssessment.vendor_tier,
    review_frequency: aiAssessment.recommended_review_frequency,
    enriched_at: new Date().toISOString()
  }
}];
